function generateSnapshotState(): string {
  return `/// <summary>
/// SnapshotState is the state payload of a snapshot — root, session,
/// chat, terminal, changeset, resource-watch, or annotations state. Read
/// probes for distinctive fields in an order where no probe shadows another
/// (chat → session → terminal → changeset → resource-watch → annotations → root).
/// </summary>
[JsonConverter(typeof(SnapshotStateConverter))]
public sealed class SnapshotState
{
    /// <summary>Root state variant, when populated.</summary>
    public RootState? Root { get; set; }

    /// <summary>Session state variant, when populated.</summary>
    public SessionState? Session { get; set; }

    /// <summary>Chat state variant, when populated.</summary>
    public ChatState? Chat { get; set; }

    /// <summary>Terminal state variant, when populated.</summary>
    public TerminalState? Terminal { get; set; }

    /// <summary>Changeset state variant, when populated.</summary>
    public ChangesetState? Changeset { get; set; }

    /// <summary>Resource-watch state variant, when populated.</summary>
    public ResourceWatchState? ResourceWatch { get; set; }

    /// <summary>Annotations state variant, when populated.</summary>
    public AnnotationsState? Annotations { get; set; }
}

/// <summary>System.Text.Json converter for the SnapshotState shape-probed union.</summary>
internal sealed class SnapshotStateConverter : JsonConverter<SnapshotState>
{
    public override SnapshotState Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
    {
        using var doc = JsonDocument.ParseValue(ref reader);
        var root = doc.RootElement;
        var result = new SnapshotState();
        if (root.TryGetProperty("turns", out _))
        {
            result.Chat = root.Deserialize<ChatState>(options);
        }
        else if (root.TryGetProperty("summary", out _) && root.TryGetProperty("lifecycle", out _))
        {
            result.Session = root.Deserialize<SessionState>(options);
        }
        else if (root.TryGetProperty("content", out _))
        {
            result.Terminal = root.Deserialize<TerminalState>(options);
        }
        else if (root.TryGetProperty("status", out _) && root.TryGetProperty("files", out _))
        {
            result.Changeset = root.Deserialize<ChangesetState>(options);
        }
        else if (root.TryGetProperty("root", out _) && root.TryGetProperty("recursive", out _))
        {
            result.ResourceWatch = root.Deserialize<ResourceWatchState>(options);
        }
        else if (root.TryGetProperty("annotations", out _))
        {
            result.Annotations = root.Deserialize<AnnotationsState>(options);
        }
        else
        {
            result.Root = root.Deserialize<RootState>(options);
        }
        return result;
    }

    public override void Write(Utf8JsonWriter writer, SnapshotState value, JsonSerializerOptions options)
    {
        if (value.Chat is not null) { JsonSerializer.Serialize(writer, value.Chat, options); return; }
        if (value.Session is not null) { JsonSerializer.Serialize(writer, value.Session, options); return; }
        if (value.Terminal is not null) { JsonSerializer.Serialize(writer, value.Terminal, options); return; }
        if (value.Changeset is not null) { JsonSerializer.Serialize(writer, value.Changeset, options); return; }
        if (value.ResourceWatch is not null) { JsonSerializer.Serialize(writer, value.ResourceWatch, options); return; }
        if (value.Annotations is not null) { JsonSerializer.Serialize(writer, value.Annotations, options); return; }
        if (value.Root is not null) { JsonSerializer.Serialize(writer, value.Root, options); return; }
        writer.WriteNullValue();
    }
}`;
}

function generateStateFile(project: Project): string {
  const lines: string[] = [fileHeader()];

  lines.push('// ─── Enums ────────────────────────────────────────────────────────────\n');
  for (const enumName of STATE_ENUMS) {
    const decl = findEnum(project, enumName);
    if (decl) {
      lines.push(generateEnum(decl));
      lines.push('');
    }
  }

  lines.push('// ─── Classes ──────────────────────────────────────────────────────────\n');
  for (const entry of STATE_STRUCTS) {
    try {
      lines.push(
        generateClassFromInterface(project, entry.name, entry.csName, {
          omitDiscriminants: entry.omitDiscriminants,
          mutable: entry.mutable,
        }),
      );
      lines.push('');
    } catch (e) {
      lines.push(`// TODO: could not generate ${entry.name}: ${e}`);
      lines.push('');
    }
  }

  lines.push('// ─── Hand-written State Types ─────────────────────────────────────────\n');
  lines.push(SESSION_INPUT_STRUCTS_CS);
  lines.push('');

  lines.push('// ─── Discriminated Unions ─────────────────────────────────────────────\n');
  for (const u of [
    RESPONSE_PART_UNION, TOOL_CALL_STATE_UNION, TERMINAL_CLAIM_UNION,
    TERMINAL_CONTENT_PART_UNION, SESSION_INPUT_QUESTION_UNION,
    SESSION_INPUT_ANSWER_VALUE_UNION, SESSION_INPUT_ANSWER_UNION,
    CHAT_INPUT_QUESTION_UNION, CHAT_INPUT_ANSWER_VALUE_UNION, CHAT_INPUT_ANSWER_UNION,
    TOOL_RESULT_CONTENT_UNION, MESSAGE_ATTACHMENT_UNION, CUSTOMIZATION_UNION,
    CHILD_CUSTOMIZATION_UNION, CUSTOMIZATION_LOAD_STATE_UNION,
    MCP_SERVER_STATUS_UNION, TOOL_CALL_CONTRIBUTOR_UNION,
  ]) {
    lines.push(generateDiscriminatedUnion(u));
    lines.push('');
  }
  lines.push(CHAT_ORIGIN_UNION_CS);
  lines.push('');
  lines.push(generateSnapshotState());
  lines.push('');

  return lines.join('\n');
}

