function generateSessionTruncatedActionClass(): string {
  return `/// <summary>Truncates a session's history. If \`turnId\` is provided, all turns after that
/// turn are removed and the specified turn is kept. If \`turnId\` is omitted, all
/// turns are removed.
///
/// If there is an active turn it is silently dropped and the session status
/// returns to \`idle\`.
///
/// Common use-case: truncate old data then dispatch a new
/// \`session/turnStarted\` with an edited message.</summary>
public sealed record SessionTruncatedAction
{
    public ActionType Type { get; init; }

    /// <summary>Keep turns up to and including this turn. Omit to clear all turns.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? TurnId { get; init; }
}`;
}

function generateSessionToolCallContentChangedActionClass(): string {
  return `/// <summary>Partial content produced while a tool is still executing.
///
/// Replaces the \`content\` array on the running tool call state. Clients can
/// use this to display live feedback (e.g. a terminal reference) before the
/// tool completes.
///
/// For client-provided tools (where \`toolClientId\` is set on the tool call state),
/// the owning client dispatches this action to stream intermediate content while
/// executing. The server SHOULD reject this action if the dispatching client does
/// not match \`toolClientId\`.</summary>
public sealed record SessionToolCallContentChangedAction
{
    /// <summary>Turn identifier</summary>
    public required string TurnId { get; init; }

    /// <summary>Tool call identifier</summary>
    public required string ToolCallId { get; init; }

    /// <summary>Additional provider-specific metadata for this tool call.
    ///
    /// Clients MAY look for well-known keys here to provide enhanced UI.
    /// For example, a \`ptyTerminal\` key with \`{ input: string; output: string }\`
    /// indicates the tool operated on a terminal (both \`input\` and \`output\` may
    /// contain escape sequences).</summary>
    [JsonPropertyName("_meta")]
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public Dictionary<string, JsonElement>? Meta { get; init; }

    public ActionType Type { get; init; }

    /// <summary>The current partial content for the running tool call</summary>
    public required List<ToolResultContent> Content { get; init; }
}`;
}

