function generateActionEnvelope(): string {
  return `/// <summary>
/// ActionEnvelope wraps every action with the channel URI it belongs to,
/// the server-assigned monotonic sequence number, and an optional origin.
/// </summary>
public sealed record ActionEnvelope
{
    public required string Channel { get; init; }

    public required StateAction Action { get; init; }

    public long ServerSeq { get; init; }

    /// <summary>The origin of the action. Required-nullable in the wire schema
    /// (<c>ActionOrigin | undefined</c>): omitted when absent (server-originated),
    /// never serialized as <c>null</c>.</summary>
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ActionOrigin? Origin { get; init; }

    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public string? RejectionReason { get; init; }
}`;
}

function generateActionsUnion(): string {
  const cfg: UnionConfig = {
    name: 'StateAction',
    discriminantField: 'type',
    doc: 'StateAction is the discriminated union of every state action.',
    variants: ACTION_VARIANTS.map((v) => ({
      variantName: v.variantName,
      innerType: v.tsInterface === '_merged_' ? 'SessionToolCallConfirmedAction'
               : v.tsInterface === '_merged_chat_' ? 'ChatToolCallConfirmedAction'
               : v.tsInterface === '_hand_written_session_truncated_' ? 'SessionTruncatedAction'
               : v.tsInterface === '_hand_written_session_toolcallcontent_' ? 'SessionToolCallContentChangedAction'
               : v.tsInterface === '_hand_written_session_action_' ? `${v.variantName}Action`
               : stripIPrefix(v.tsInterface),
      wireValue: v.type,
    })),
    unknown: true,
  };
  return generateDiscriminatedUnion(cfg);
}

function generateActionsFile(project: Project): string {
  const lines: string[] = [fileHeader()];

  lines.push('// ─── ActionType ──────────────────────────────────────────────────────\n');
  const actionTypeEnum = findEnum(project, 'ActionType');
  lines.push(actionTypeEnum ? generateEnum(actionTypeEnum) : '// TODO: ActionType enum not found');
  lines.push('');

  lines.push('// ─── Action Envelope ─────────────────────────────────────────────────\n');
  lines.push(generateClassFromInterface(project, 'ActionOrigin'));
  lines.push('');
  lines.push(generateActionEnvelope());
  lines.push('');

  const priorPartials = new Set(requiredPartialStructs);

  lines.push('// ─── Action Payloads ─────────────────────────────────────────────────\n');
  let handWrittenSessionActionsEmitted = false;
  for (const v of ACTION_VARIANTS) {
    if (v.tsInterface === '_merged_') {
      lines.push(generateMergedToolCallConfirmedClass());
      lines.push('');
      continue;
    }
    if (v.tsInterface === '_merged_chat_') {
      lines.push(generateMergedChatToolCallConfirmedClass());
      lines.push('');
      continue;
    }
    if (v.tsInterface === '_hand_written_session_truncated_') {
      lines.push(generateSessionTruncatedActionClass());
      lines.push('');
      continue;
    }
    if (v.tsInterface === '_hand_written_session_toolcallcontent_') {
      lines.push(generateSessionToolCallContentChangedActionClass());
      lines.push('');
      continue;
    }
    if (v.tsInterface === '_hand_written_session_action_') {
      // All 19 hand-written session action types are emitted as a single block.
      // Only emit on the first encounter; skip subsequent occurrences.
      if (!handWrittenSessionActionsEmitted) {
        lines.push(SESSION_ACTION_TYPES_CS);
        lines.push('');
        handWrittenSessionActionsEmitted = true;
      }
      continue;
    }
    try {
      lines.push(generateClassFromInterface(project, v.tsInterface, undefined, { includeDiscriminants: true }));
      lines.push('');
    } catch (e) {
      lines.push(`// TODO: could not generate ${v.tsInterface}: ${e}`);
      lines.push('');
    }
  }

  // Emit any Partial<T> types that were discovered processing actions (e.g. SessionChatUpdatedAction
  // uses Partial<ChatSummary>), so they are available in this file rather than waiting for the
  // notifications file (which comes later and only emits its own newly-discovered partials).
  const newPartials = [...requiredPartialStructs].filter((n) => !priorPartials.has(n));
  if (newPartials.length > 0) {
    lines.push('// ─── Partial Summaries (action-discovered) ───────────────────────────\n');
    for (const tsName of newPartials) {
      try {
        lines.push(generatePartialClass(project, tsName));
        lines.push('');
      } catch (e) {
        lines.push(`// TODO: could not generate Partial<${tsName}>: ${e}`);
        lines.push('');
      }
    }
  }

  lines.push('// ─── StateAction Union ───────────────────────────────────────────────\n');
  lines.push(generateActionsUnion());
  lines.push('');

  return lines.join('\n');
}

