function generateErrorsFile(project: Project): string {
  // Derive both code lists from types/common/errors.ts (the single source of
  // truth) rather than hand-maintaining a copy here — a new code added to
  // errors.ts then appears automatically instead of silently going missing
  // (the cause of `Conflict` being absent before).
  const { jsonRpc, ahp } = readErrorCodes(project);
  const xml = (s: string): string =>
    s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  const emitCodes = (
    summary: string,
    className: string,
    codes: readonly { name: string; code: number; doc: string }[],
  ): string => {
    const lines = [`/// <summary>${summary}</summary>`, `public static class ${className}`, '{'];
    for (const { name, code, doc } of codes) {
      if (doc) lines.push(`    /// <summary>${xml(doc)}</summary>`);
      lines.push(`    public const int ${name} = ${code};`);
    }
    lines.push('}');
    return lines.join('\n');
  };
  return `${fileHeader()}
${emitCodes('Standard JSON-RPC 2.0 error codes.', 'JsonRpcErrorCodes', jsonRpc)}

${emitCodes('AHP application-specific error codes (above the JSON-RPC reserved range).', 'AhpErrorCodes', ahp)}

/// <summary>Detail payload of an AuthRequired (-32007) error.</summary>
public sealed record AuthRequiredErrorData
{
    public required List<ProtectedResourceMetadata> Resources { get; init; }
}

/// <summary>Detail payload of a PermissionDenied (-32009) error.</summary>
public sealed record PermissionDeniedErrorData
{
    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public ResourceRequestParams? Request { get; init; }
}

/// <summary>Detail payload of an UnsupportedProtocolVersion (-32005) error.</summary>
public sealed record UnsupportedProtocolVersionErrorData
{
    public required List<string> SupportedVersions { get; init; }
}
`;
}

// ─── Messages File Generator ─────────────────────────────────────────────────

function generateMessagesFile(): string {
  return `${fileHeader()}
/// <summary>The canonical JSON-RPC version literal (<c>"2.0"</c>).</summary>
public static class JsonRpc
{
    /// <summary>The sole allowed value of the <c>jsonrpc</c> field.</summary>
    public const string Version = "2.0";
}

/// <summary>A JSON-RPC 2.0 request (method + id).</summary>
public sealed class JsonRpcRequest
{
    // jsonrpc diverges from camelCase(JsonRpcVersion); keep the explicit name.
    [JsonPropertyName("jsonrpc")]
    public string JsonRpcVersion { get; set; } = JsonRpc.Version;

    public ulong Id { get; set; }

    public string Method { get; set; } = "";

    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public JsonElement? Params { get; set; }
}

/// <summary>A JSON-RPC 2.0 success response.</summary>
public sealed class JsonRpcSuccessResponse
{
    [JsonPropertyName("jsonrpc")]
    public string JsonRpcVersion { get; set; } = JsonRpc.Version;

    public ulong Id { get; set; }

    public JsonElement Result { get; set; }
}

/// <summary>A JSON-RPC 2.0 error response.</summary>
public sealed class JsonRpcErrorResponse
{
    [JsonPropertyName("jsonrpc")]
    public string JsonRpcVersion { get; set; } = JsonRpc.Version;

    public ulong Id { get; set; }

    public JsonRpcErrorObject Error { get; set; } = new();
}

/// <summary>The standard JSON-RPC 2.0 error object.</summary>
public sealed class JsonRpcErrorObject
{
    public int Code { get; set; }

    public string Message { get; set; } = "";

    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public JsonElement? Data { get; set; }
}

/// <summary>A JSON-RPC 2.0 notification (method, no id).</summary>
public sealed class JsonRpcNotification
{
    [JsonPropertyName("jsonrpc")]
    public string JsonRpcVersion { get; set; } = JsonRpc.Version;

    public string Method { get; set; } = "";

    [JsonIgnore(Condition = JsonIgnoreCondition.WhenWritingNull)]
    public JsonElement? Params { get; set; }
}

/// <summary>
/// A discriminated union over the four JSON-RPC message shapes. The active
/// variant is chosen by JSON-RPC 2.0's shape rules:
/// request (id + method), notification (method, no id),
/// success-response (id + result), error-response (id + error).
/// </summary>
[JsonConverter(typeof(JsonRpcMessageConverter))]
public sealed class JsonRpcMessage
{
    public JsonRpcRequest? Request { get; set; }
    public JsonRpcSuccessResponse? SuccessResponse { get; set; }
    public JsonRpcErrorResponse? ErrorResponse { get; set; }
    public JsonRpcNotification? Notification { get; set; }
}

/// <summary>System.Text.Json converter for the shape-probed JsonRpcMessage union.</summary>
internal sealed class JsonRpcMessageConverter : JsonConverter<JsonRpcMessage>
{
    public override JsonRpcMessage Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
    {
        using var doc = JsonDocument.ParseValue(ref reader);
        var root = doc.RootElement;
        bool hasMethod = root.TryGetProperty("method", out _);
        bool hasId = root.TryGetProperty("id", out _);
        bool hasResult = root.TryGetProperty("result", out _);
        bool hasError = root.TryGetProperty("error", out _);
        var msg = new JsonRpcMessage();
        if (hasMethod && hasId)
        {
            msg.Request = root.Deserialize<JsonRpcRequest>(options);
        }
        else if (hasMethod)
        {
            msg.Notification = root.Deserialize<JsonRpcNotification>(options);
        }
        else if (hasError)
        {
            msg.ErrorResponse = root.Deserialize<JsonRpcErrorResponse>(options);
        }
        else if (hasResult)
        {
            msg.SuccessResponse = root.Deserialize<JsonRpcSuccessResponse>(options);
        }
        else
        {
            throw new JsonException("JSON-RPC message has no method/result/error");
        }
        return msg;
    }

    public override void Write(Utf8JsonWriter writer, JsonRpcMessage value, JsonSerializerOptions options)
    {
        if (value.Request is not null) { JsonSerializer.Serialize(writer, value.Request, options); return; }
        if (value.SuccessResponse is not null) { JsonSerializer.Serialize(writer, value.SuccessResponse, options); return; }
        if (value.ErrorResponse is not null) { JsonSerializer.Serialize(writer, value.ErrorResponse, options); return; }
        if (value.Notification is not null) { JsonSerializer.Serialize(writer, value.Notification, options); return; }
        writer.WriteNullValue();
    }
}
`;
}

// ─── Version File Generator ──────────────────────────────────────────────────

function generateVersionFile(project: Project): string {
  const { current, supported } = readProtocolVersions(project);
  const supportedLiteral = supported.map((v) => `        ${JSON.stringify(v)},`).join('\n');
  return `${fileHeader()}
/// <summary>Protocol version constants for the Agent Host Protocol.</summary>
public static class ProtocolVersion
{
    /// <summary>
    /// The current protocol version (SemVer MAJOR.MINOR.PATCH) this
    /// generated source speaks.
    /// </summary>
    public const string Current = ${JSON.stringify(current)};

    private static readonly string[] s_supported =
    {
${supportedLiteral}
    };

    /// <summary>
    /// Every protocol version this client is willing to negotiate, ordered
    /// most-preferred-first. The first entry always equals <see cref="Current"/>.
    /// A fresh copy is returned on every call so callers may mutate it freely.
    /// </summary>
    public static IReadOnlyList<string> Supported => (string[])s_supported.Clone();

    /// <summary>The well-known channel URI for the root channel.</summary>
    public const string RootResourceUri = "ahp-root://";
}
`;
}

// ─── Exhaustiveness ─────────────────────────────────────────────────────────

function collectEnumNames(project: Project): void {
  for (const name of [...STATE_ENUMS, ...COMMAND_ENUMS, ...NOTIFICATION_ENUMS, 'ActionType']) {
    ALL_ENUM_NAMES.add(name);
  }
  // ChildCustomizationType is aliased to CustomizationType (already counted).
  void project;
}

function checkExhaustiveness(project: Project): void {
  const protocolModules = ['state.ts', 'actions.ts', 'commands.ts', 'notifications.ts', 'errors.ts'];
  const imported = new Set<string>();
  for (const baseName of protocolModules) {
    for (const sf of findProtocolSourceFiles(project, baseName)) {
      for (const decl of sf.getInterfaces()) {
        if (decl.isExported()) imported.add(decl.getName());
      }
      for (const decl of sf.getTypeAliases()) {
        if (decl.isExported()) imported.add(decl.getName());
      }
    }
  }

  const coveredByLists = new Set<string>([
    ...STATE_STRUCTS.map((s) => s.name),
    ...STATE_ENUMS,
    ...COMMAND_STRUCTS.map((s) => s.name),
    ...COMMAND_ENUMS,
    ...NOTIFICATION_STRUCTS,
    ...NOTIFICATION_ENUMS,
    ...ACTION_VARIANTS
      .filter((v) => !v.tsInterface.startsWith('_'))
      .map((v) => v.tsInterface),
  ]);

  const knownSpecial = new Set<string>([
    'URI', 'JsonPrimitive', 'BaseParams', 'StringOrMarkdown', 'ToolCallState', 'StateAction',
    'ActionEnvelope', 'ActionOrigin', 'ResponsePart', 'ToolResultContent',
    'SessionToolCallApprovedAction', 'SessionToolCallDeniedAction',
    'SessionToolCallConfirmedAction', 'PingParams', 'TerminalClaim',
    'TerminalContentPart', 'SessionInputQuestion', 'SessionInputAnswerValue',
    'SessionInputAnswer', 'MessageAttachment', 'MessageAttachmentBase',
    'Customization', 'ChildCustomization', 'ChildCustomizationType',
    'CustomizationLoadState', 'McpServerState', 'ToolCallContributor',
    'ReconnectResult', 'AuthRequiredErrorData',
    'PermissionDeniedErrorData', 'UnsupportedProtocolVersionErrorData',
    'AhpError', 'AhpErrorDetailsMap', 'AhpErrorCode', 'AhpErrorCodeWithData',
    'JsonRpcErrorCode', 'ChangesetOperationTarget',
    'ChatOrigin', 'ChatInputQuestion', 'ChatInputAnswerValue', 'ChatInputAnswer',
    'ChatToolCallConfirmedAction', 'ChatToolCallApprovedAction', 'ChatToolCallDeniedAction',
    'ChatForkSource', 'ChatAction',
    // SessionMetadata is the shared base interface whose fields are denormalized
    // (inlined) into both SessionState and SessionSummary; it has no standalone
    // C# record by design.
    'SessionMetadata',
  ]);

  const missing = [...imported].filter((n) => !coveredByLists.has(n) && !knownSpecial.has(n));
  if (missing.length > 0) {
    console.warn(
      'generate-csharp.ts exhaustiveness: the following types are exported from ' +
        'the protocol source modules but not covered by the C# generator:\n' +
        missing.map((n) => `  - ${n}`).join('\n'),
    );
  }
}

// ─── Telemetry Names File Generator ──────────────────────────────────────────

function generateTelemetryFile(project: Project): string {
  const t = readTelemetry(project);
  const body: string[] = [];
  // XML-escape a description for a /// <summary> doc comment.
  const xml = (s: string): string => s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  const doc = (text: string): void => {
    if (text) body.push(`    /// <summary>${xml(text)}</summary>`);
  };
  body.push('/// <summary>');
  body.push('/// Telemetry NAMES this client emits about its own operation, codegen\'d from the');
  body.push('/// client-private registry <c>clients/dotnet/codegen/telemetry/registry.ts</c> so the');
  body.push('/// span / metric / attribute names stay in one place. Names only; the');
  body.push('/// ActivitySource / Meter wiring is hand-written in <c>Telemetry.cs</c>. The registry');
  body.push('/// is structured for promotion to a shared cross-client contract if AHP ever specs');
  body.push('/// one (see issue #239).');
  body.push('/// </summary>');
  body.push('public static class AhpTelemetryNames');
  body.push('{');
  doc(t.source.doc);
  body.push(`    public const string Source = ${JSON.stringify(t.source.value)};`);
  body.push('');
  body.push('    // ── Span names ──');
  for (const span of t.spans) {
    doc(span.doc);
    body.push(`    public const string ${span.id}Span = ${JSON.stringify(span.value)};`);
  }
  body.push('');
  body.push('    // ── Metric names ──');
  for (const metric of t.metrics) {
    doc(metric.doc);
    body.push(`    public const string ${metric.id} = ${JSON.stringify(metric.value)};`);
  }
  body.push('');
  body.push('    // ── Metric units ──');
  for (const metric of t.metrics) {
    doc(`Unit for the \`${metric.value}\` metric.`);
    body.push(`    public const string ${metric.id}Unit = ${JSON.stringify(metric.unit)};`);
  }
  body.push('');
  body.push('    // ── Metric descriptions ──');
  body.push('    // Single source for the human-readable instrument description, used both as');
  body.push('    // the doc-comment summary above each metric name AND as the runtime');
  body.push('    // `description:` passed to Meter.CreateX in Telemetry.cs — so the two cannot drift.');
  for (const metric of t.metrics) {
    doc(`Description for the \`${metric.value}\` metric.`);
    body.push(`    public const string ${metric.id}Description = ${JSON.stringify(metric.doc)};`);
  }
  body.push('');
  body.push('    // ── Attribute keys ──');
  for (const attr of t.attributes) {
    doc(attr.doc);
    body.push(`    public const string Attr${attr.id} = ${JSON.stringify(attr.value)};`);
  }
  body.push('');
  body.push('    // ── Attribute values ──');
  for (const grp of t.values) {
    for (const member of grp.members) {
      doc(member.doc);
      body.push(`    public const string ${grp.group}${member.id} = ${JSON.stringify(member.value)};`);
    }
  }
  body.push('}');
  return `${fileHeader()}\n${body.join('\n')}\n`;
}

// ─── Main Entry Point ────────────────────────────────────────────────────────

export function generateCSharpPackage(project: Project, outputDir: string): void {
  collectEnumNames(project);
  checkExhaustiveness(project);

  // The telemetry-name registry is a .NET-client-private codegen source (it lives
  // under the client tree, not in `types/`, because AHP has not specced a
  // cross-client self-instrumentation contract — see #239). The shared ts-morph
  // project is built from `types/tsconfig.json`, so add the client-private
  // registry here; `readTelemetry` then locates it by its `/telemetry/registry.ts`
  // path suffix. If AHP ever specs a shared contract, move this file back to
  // `types/telemetry/registry.ts` and drop this line.
  project.addSourceFileAtPath(path.join(outputDir, 'codegen', 'telemetry', 'registry.ts'));

  const srcDir = path.join(outputDir, 'src', 'AgentHostProtocol.Abstractions', 'Generated');
  fs.mkdirSync(srcDir, { recursive: true });

  fs.writeFileSync(path.join(srcDir, 'State.generated.cs'), generateStateFile(project));
  fs.writeFileSync(path.join(srcDir, 'Actions.generated.cs'), generateActionsFile(project));
  fs.writeFileSync(path.join(srcDir, 'Commands.generated.cs'), generateCommandsFile(project));
  fs.writeFileSync(path.join(srcDir, 'Notifications.generated.cs'), generateNotificationsFile(project));
  fs.writeFileSync(path.join(srcDir, 'Errors.generated.cs'), generateErrorsFile(project));
  fs.writeFileSync(path.join(srcDir, 'Messages.generated.cs'), generateMessagesFile());
  fs.writeFileSync(path.join(srcDir, 'Version.generated.cs'), generateVersionFile(project));
  fs.writeFileSync(path.join(srcDir, 'Telemetry.generated.cs'), generateTelemetryFile(project));
}
